                builder.Append('/');
            }
            builder.Append(ExecutionTransactionMessage.BlockLength);
            builder.Append("):");

            builder.Append("UpdateTime=");
            builder.Append(this.UpdateTime);
            builder.Append('|');
            builder.Append("Venue=");
            builder.Append(this.Venue);
            builder.Append('|');
            builder.Append("Account=");
            builder.Append("'");
            for (int i = 0; i < AccountLength && this.GetAccount(i) > 0; ++i)
            {
                builder.Append((char)this.GetAccount(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("OrderId=");
            builder.Append("'");
            for (int i = 0; i < OrderIdLength && this.GetOrderId(i) > 0; ++i)
            {
                builder.Append((char)this.GetOrderId(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("Underlying=");
            builder.Append("'");
            for (int i = 0; i < UnderlyingLength && this.GetUnderlying(i) > 0; ++i)
            {
                builder.Append((char)this.GetUnderlying(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("Symbol=");
            builder.Append("'");
            for (int i = 0; i < SymbolLength && this.GetSymbol(i) > 0; ++i)
            {
                builder.Append((char)this.GetSymbol(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("Trader=");
            builder.Append("'");
            for (int i = 0; i < TraderLength && this.GetTrader(i) > 0; ++i)
            {
                builder.Append((char)this.GetTrader(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("Price=");
            if (this.Price != null)
            {
                this.Price.BuildString(builder);
            }
            else
            {
                builder.Append("null");
            }
            builder.Append('|');
            builder.Append("Side=");
            builder.Append(this.Side);
            builder.Append('|');
            builder.Append("OrderQty=");
            builder.Append(this.OrderQty);
            builder.Append('|');
            builder.Append("FilledQty=");
            builder.Append(this.FilledQty);
            builder.Append('|');
            builder.Append("ExecutionType=");
            builder.Append(this.ExecutionType);
            builder.Append('|');
            builder.Append("Multiplier=");
            if (this.Multiplier != null)
            {
                this.Multiplier.BuildString(builder);
            }
            else
            {
                builder.Append("null");
            }

            this.Limit = originalLimit;

        }
    }
}
